#!/usr/bin/env python
"""
MABE Bootstrap: Novel Materials Validation
==========================================
Patches unified_scorer_v2.py to handle novel hosts not in HOST_DB.
Adds test_novel_materials.py with 19 tests covering:
  - _synthesize_host_dict() unit tests (7)
  - Novel host scoring integration tests (12) including MOFs
  - Regression guards for existing HOST_DB hosts (2 = beta-CD, CB7 unchanged)

Three patches to unified_scorer_v2.py:
  1. _synthesize_host_dict(): builds HOST_DB-compatible dict from UC cavity fields
     (sphere approximation — conservative, underpredicts SASA for elongated cavities)
  2. HOST_DB fallback in _compute_hg_terms(): when _resolve_host_key fails but
     cavity_volume_A3 > 0, synthesize host dict and proceed
  3. SASA fallback: relaxes guest_smiles guard to allow scoring when
     guest_sasa_nonpolar_A2 is pre-populated (e.g., for CO2 without SMILES)

Known limitation documented in tests:
  H-bond at "neutral" portal incurs desolvation cost that exceeds bond benefit
  in CD/CB-calibrated parameters. MOF amine-CO2 H-bonds need separate
  parameterization to predict functionalization advantage.

Zero regression: all 5 existing unified_scorer_v2 tests pass unchanged.

Supersedes: (none — first novel materials bootstrap)
Requires: Current MABE repo with unified_scorer_v2.py

Usage (PowerShell):
  python bootstrap_novel_materials.py
  python -m pytest tests/test_novel_materials.py tests/test_unified_scorer_v2.py -v
"""
import base64, os, sys

def write_b64(path, data_b64):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'wb') as f:
        f.write(base64.b64decode(data_b64))
    print(f"  Written: {path} ({os.path.getsize(path)} bytes)")

def main():
    # Detect repo root
    root = os.path.dirname(os.path.abspath(__file__))
    if not os.path.isfile(os.path.join(root, 'core', 'universal_schema.py')):
        # Try parent
        root = os.path.dirname(root)
    if not os.path.isfile(os.path.join(root, 'core', 'universal_schema.py')):
        print("ERROR: Run from MABE repo root or place bootstrap in repo root.")
        sys.exit(1)

    print("MABE Bootstrap: Novel Materials Validation")
    print("=" * 50)

    # Backup
    scorer_path = os.path.join(root, 'core', 'unified_scorer_v2.py')
    bak_path = scorer_path + '.pre_novel_materials.bak'
    if not os.path.isfile(bak_path):
        import shutil
        shutil.copy2(scorer_path, bak_path)
        print(f"  Backup: {bak_path}")

    # Write patched scorer
    write_b64(scorer_path, "")

    # Write test file
    write_b64(os.path.join(root, 'tests', 'test_novel_materials.py'), "")

    print()
    print("Validation:")
    print("  python -m pytest tests/test_novel_materials.py tests/test_unified_scorer_v2.py -v")
    print()
    print("Expected: 24 passed (19 novel + 5 existing), 0 failed")


if __name__ == "__main__":
    main()